query:
query($cursor: String) {
	transactions(
		tags: [
			{ name: "Content-Type", values: ["video/*", "image/*"], match: WILDCARD }
		]
		sort: HEIGHT_DESC
		after: $cursor
		first: 100
	) {
		pageInfo { hasNextPage }
		edges {
			cursor
			node {
				id
				data { size type }
				tags { name value }
				block { height }
				parent { id }
				owner { address }
				ingested_at
			}
		}
	}
}
